const searchArticles = `-- name: SearchArticles :many
SELECT a.id, a.source_id, a.title, a.link, a.language, a.published_at,
       ts_headline('simple', a.title || ' ' || COALESCE(a.content_text, ''),
                   plainto_tsquery('simple', $1) || cjk_tsquery($1),
                   'MaxWords=20, MinWords=6') AS headline
FROM articles a
JOIN sources s ON a.source_id = s.id
WHERE s.user_id = $2
  AND s.deleted_at IS NULL
  AND a.search_vec @@ (plainto_tsquery('simple', $1) || cjk_tsquery($1))
ORDER BY ts_rank(a.search_vec, plainto_tsquery('simple', $1) || cjk_tsquery($1)) DESC
LIMIT 100
`

